import React, { useCallback, useContext, useEffect, useMemo, useState, useRef } from "react";
import { createPortal } from "react-dom";
import CalendarHeatmap from "react-calendar-heatmap";
import { TimerContext } from "../../context/TimerContext";
import { AuthContext } from "../../context/AuthContext";
import "react-calendar-heatmap/dist/styles.css";
import axios from "../../api/axios";

// SVG Icons for stats
const StatIcons = {
  Calendar: () => (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <rect x="3" y="4" width="18" height="18" rx="2" ry="2" />
      <line x1="16" y1="2" x2="16" y2="6" />
      <line x1="8" y1="2" x2="8" y2="6" />
      <line x1="3" y1="10" x2="21" y2="10" />
    </svg>
  ),
  Flame: () => (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M8.5 14.5A2.5 2.5 0 0011 12c0-1.38-.5-2-1-3-1.072-2.143-.224-4.054 2-6 .5 2.5 2 4.9 4 6.5 2 1.6 3 3.5 3 5.5a7 7 0 11-14 0c0-1.153.433-2.294 1-3a2.5 2.5 0 002.5 2.5z" />
    </svg>
  ),
  Trophy: () => (
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
      <path d="M6 9H4.5a2.5 2.5 0 010-5H6" />
      <path d="M18 9h1.5a2.5 2.5 0 000-5H18" />
      <path d="M4 22h16" />
      <path d="M10 14.66V17c0 .55-.47.98-.97 1.21C7.85 18.75 7 20.24 7 22" />
      <path d="M14 14.66V17c0 .55.47.98.97 1.21C16.15 18.75 17 20.24 17 22" />
      <path d="M18 2H6v7a6 6 0 0012 0V2z" />
    </svg>
  ),
};

const ReadingHeatmap = () => {
  const { streak, fetchStreak, timerError } = useContext(TimerContext);
  const { token } = useContext(AuthContext);
  const containerRef = useRef(null);
  const [tip, setTip] = useState(null);

  const fmtIST = (d) =>
    new Date(d).toLocaleDateString("en-CA", { timeZone: "Asia/Kolkata" });
  const todayIST = () =>
    new Date().toLocaleDateString("en-CA", { timeZone: "Asia/Kolkata" });

  useEffect(() => {
    if (token) fetchStreak();
  }, [token]);

  const [dayTotals, setDayTotals] = useState({});
  const [maxTotal, setMaxTotal] = useState(0);
  const end = new Date();
  const start = new Date();
  start.setDate(end.getDate() - 180);

  useEffect(() => {
    const from = new Date(start);
    from.setHours(0, 0, 0, 0);
    const to = new Date(end);
    to.setHours(23, 59, 59, 999);
    const fromStr = from.toISOString();
    const toStr = to.toISOString();
    let cancelled = false;
    (async () => {
      try {
        const res = await axios.get(
          `/readingSessions?from=${encodeURIComponent(fromStr)}&to=${encodeURIComponent(toStr)}`
        );
        const totals = {};
        for (const s of res.data || []) {
          const dateSource = s.date || s.startTime;
          const key = dateSource
            ? new Date(dateSource).toLocaleDateString("en-CA", {
                timeZone: "Asia/Kolkata",
              })
            : "";
          if (!key) continue;
          totals[key] = (totals[key] || 0) + (Number(s.duration) || 0);
        }
        if (!cancelled) {
          setDayTotals(totals);
          const max = Object.values(totals).reduce((m, v) => Math.max(m, v), 0);
          setMaxTotal(max);
        }
      } catch (e) {
        // silent fail
      }
    })();
    return () => {
      cancelled = true;
    };
  }, []);

  const values = useMemo(() => {
    return Object.entries(dayTotals).map(([date, total]) => ({
      date,
      count: total,
    }));
  }, [dayTotals]);

  const getTipContent = useCallback((value) => {
    if (!value?.date) return null;
    const d = new Date(value.date + "T00:00:00");
    const formatted = d.toLocaleDateString("en-US", {
      weekday: "short",
      month: "short",
      day: "numeric",
      timeZone: "Asia/Kolkata",
    });
    const mins = Math.round((Number(value.count) || 0) / 60);
    const duration = mins > 0 ? `${mins} min focused` : "No activity";
    let intensity = "None";
    if (mins > 0 && mins <= 15) intensity = "Light";
    else if (mins > 15 && mins <= 30) intensity = "Steady";
    else if (mins > 30 && mins <= 60) intensity = "Strong";
    else if (mins > 60) intensity = "Peak";
    return { date: formatted, duration, intensity, key: value.date };
  }, []);

  const placeTip = useCallback((event, value) => {
    const content = getTipContent(value);
    if (!content) return;

    const pad = 14;
    const tipWidth = 220;
    const tipHeight = 78;
    let x = event.clientX + 14;
    let y = event.clientY + 14;

    if (x + tipWidth > window.innerWidth - pad) {
      x = event.clientX - tipWidth - 14;
    }
    if (y + tipHeight > window.innerHeight - pad) {
      y = event.clientY - tipHeight - 14;
    }
    if (x < pad) x = pad;
    if (y < pad) y = pad;

    setTip({ x, y, ...content });
  }, [getTipContent]);

  const { totalActive, currentStreak, maxStreak } = useMemo(() => {
    if (!streak || streak.length === 0)
      return { totalActive: 0, currentStreak: 0, maxStreak: 0 };
    const activeDates = new Set(
      streak
        .filter((d) => d.isActive)
        .map((d) => (d.date ? fmtIST(d.date) : ""))
    );
    if (activeDates.size === 0)
      return { totalActive: 0, currentStreak: 0, maxStreak: 0 };

    const shiftIST = (str, deltaDays) => {
      const dt = new Date(str + "T00:00:00+05:30");
      dt.setDate(dt.getDate() + deltaDays);
      return dt.toLocaleDateString("en-CA", { timeZone: "Asia/Kolkata" });
    };

    const todayStr = todayIST();
    let cur = 0;
    let cursor = todayStr;
    while (activeDates.has(cursor)) {
      cur += 1;
      cursor = shiftIST(cursor, -1);
    }

    const sorted = Array.from(activeDates).sort();
    let max = 0;
    let run = 0;
    let prev = null;
    for (const s of sorted) {
      if (!prev || s !== shiftIST(prev, 1)) {
        run = 1;
      } else {
        run += 1;
      }
      if (run > max) max = run;
      prev = s;
    }
    return {
      totalActive: activeDates.size,
      currentStreak: cur,
      maxStreak: Math.max(max, cur),
    };
  }, [streak]);

  return (
    <div className="dd-heatmap" ref={containerRef}>
      {/* Header */}
      <div className="dd-heatmap__header">
        <div className="dd-heatmap__title-wrap">
          <h3 className="dd-heatmap__title">
            <span className="dd-heatmap__title-icon">
              <StatIcons.Calendar />
            </span>
            Streak Map
          </h3>
          <p className="dd-heatmap__subtitle">Your focus consistency over the last 6 months</p>
        </div>
        <span className="dd-heatmap__range-pill">Last 180 days</span>
        <div className="dd-heatmap__stats">
          <div className="dd-heatmap__stat">
            <span className="dd-heatmap__stat-icon dd-heatmap__stat-icon--days">
              <StatIcons.Calendar />
            </span>
            <div className="dd-heatmap__stat-content">
              <span className="dd-heatmap__stat-value">{totalActive}</span>
              <span className="dd-heatmap__stat-label">Active Days</span>
            </div>
          </div>
          <div className="dd-heatmap__stat">
            <span className="dd-heatmap__stat-icon dd-heatmap__stat-icon--streak">
              <StatIcons.Flame />
            </span>
            <div className="dd-heatmap__stat-content">
              <span className="dd-heatmap__stat-value">{currentStreak}</span>
              <span className="dd-heatmap__stat-label">Current Streak</span>
            </div>
          </div>
          <div className="dd-heatmap__stat">
            <span className="dd-heatmap__stat-icon dd-heatmap__stat-icon--max">
              <StatIcons.Trophy />
            </span>
            <div className="dd-heatmap__stat-content">
              <span className="dd-heatmap__stat-value">{maxStreak}</span>
              <span className="dd-heatmap__stat-label">Best Streak</span>
            </div>
          </div>
        </div>
      </div>

      {timerError && (
        <div className="dd-heatmap__error">{timerError}</div>
      )}

      {/* Heatmap */}
      <div className="dd-heatmap__chart" onMouseLeave={() => setTip(null)}>
        <CalendarHeatmap
          startDate={start}
          endDate={end}
          values={values}
          gutterSize={2}
          showWeekdayLabels={false}
          showMonthLabels={true}
          classForValue={(v) => {
            const minutes = (Number(v?.count) || 0) / 60;
            let level = 0;
            if (minutes > 0 && minutes <= 15) level = 1;
            else if (minutes > 15 && minutes <= 30) level = 2;
            else if (minutes > 30 && minutes <= 60) level = 3;
            else if (minutes > 60) level = 4;
            return `dd-hc dd-hc-${level}${level > 0 ? " dd-hc--active" : ""}`;
          }}
          titleForValue={() => null}
          transformDayElement={(el, v) =>
            React.cloneElement(el, {
              onMouseEnter: (e) => {
                if (el.props.onMouseEnter) el.props.onMouseEnter(e);
                placeTip(e, v);
              },
              onMouseMove: (e) => {
                if (el.props.onMouseMove) el.props.onMouseMove(e);
                placeTip(e, v);
              },
              onMouseLeave: (e) => {
                if (el.props.onMouseLeave) el.props.onMouseLeave(e);
                setTip(null);
              },
              onFocus: (e) => {
                if (el.props.onFocus) el.props.onFocus(e);
                placeTip(e, v);
              },
              onBlur: (e) => {
                if (el.props.onBlur) el.props.onBlur(e);
                setTip(null);
              },
              tabIndex: 0,
              "aria-label": v?.date
                ? `${v.date}: ${Math.round((Number(v?.count) || 0) / 60)} minutes`
                : "No activity",
            })
          }
        />
      </div>

      {/* Legend */}
      <div className="dd-heatmap__legend">
        <span className="dd-heatmap__legend-label">Less</span>
        <div className="dd-heatmap__legend-scale">
          <span className="dd-heatmap__legend-box dd-hc-0" />
          <span className="dd-heatmap__legend-box dd-hc-1" />
          <span className="dd-heatmap__legend-box dd-hc-2" />
          <span className="dd-heatmap__legend-box dd-hc-3" />
          <span className="dd-heatmap__legend-box dd-hc-4" />
        </div>
        <span className="dd-heatmap__legend-label">More</span>
      </div>

      {/* Tooltip */}
      {tip &&
        createPortal(
          <div className="dd-heatmap__tooltip" style={{ left: tip.x, top: tip.y }}>
            <div className="dd-heatmap__tooltip-date">{tip.date}</div>
            <div className="dd-heatmap__tooltip-duration">{tip.duration}</div>
            <div className="dd-heatmap__tooltip-intensity">Intensity: {tip.intensity}</div>
          </div>,
          document.body
        )}

      <style>{`
        .dd-heatmap {
          --dd-heatmap-accent: #06b6d4;
          --dd-heatmap-accent-2: #22d3ee;
          --dd-heatmap-accent-soft: rgba(6, 182, 212, 0.18);
          position: relative;
          overflow: hidden;
          padding: 22px;
          background: var(--dd-bg-card-solid, #FFFFFF);
          border: 1px solid color-mix(in srgb, var(--dd-heatmap-accent) 24%, var(--dd-border-light, rgba(203, 213, 225, 0.55)));
          border-radius: 20px;
          box-shadow: 0 12px 30px rgba(15, 23, 42, 0.08);
        }

        .dd-heatmap__header {
          position: relative;
          display: flex;
          justify-content: flex-start;
          align-items: flex-start;
          margin-bottom: 18px;
          flex-wrap: wrap;
          gap: 14px;
        }

        .dd-heatmap__title-wrap {
          display: flex;
          flex-direction: column;
          gap: 4px;
        }

        .dd-heatmap__title {
          display: flex;
          align-items: center;
          gap: 10px;
          margin: 0;
          font-size: 16px;
          font-weight: 750;
          letter-spacing: 0.01em;
          color: var(--dd-text-primary, #0F172A);
        }

        .dd-heatmap__subtitle {
          margin: 0;
          font-size: 12px;
          color: var(--dd-text-muted, #64748B);
          letter-spacing: 0.01em;
        }

        .dd-heatmap__range-pill {
          margin-left: auto;
          display: inline-flex;
          align-items: center;
          height: 28px;
          padding: 0 12px;
          border-radius: 999px;
          border: 1px solid rgba(15, 23, 42, 0.16);
          color: #0f172a;
          font-size: 11px;
          font-weight: 700;
          letter-spacing: 0.04em;
          text-transform: uppercase;
          background: transparent;

        .dd-heatmap__title-icon {
          width: 20px;
          height: 20px;
          color: var(--dd-primary-500, #3B82F6);
        }

        .dd-heatmap__title-icon svg {
          width: 100%;
          height: 100%;
        }

        .dd-heatmap__stats {
          display: flex;
          width: 100%;
          gap: 10px;
          margin-top: 4px;
        }

        .dd-heatmap__stat {
          display: flex;
          align-items: center;
          gap: 10px;
          flex: 1;
          min-width: 120px;
          padding: 10px 12px;
          border-radius: 14px;
          border: 1px solid rgba(148, 163, 184, 0.24);
          background: color-mix(in srgb, var(--dd-bg-card-solid, #ffffff) 96%, #f8fafc);
          transition: border-color 0.24s cubic-bezier(0.22, 1, 0.36, 1);
        }

        .dd-heatmap__stat:hover {
          border-color: #0f172a;
        }

        .dd-heatmap__stat-icon {
          width: 34px;
          height: 34px;
          display: flex;
          align-items: center;
          justify-content: center;
          border-radius: 9px;
          padding: 8px;
        }

        .dd-heatmap__stat-icon svg {
          width: 100%;
          height: 100%;
        }

        .dd-heatmap__stat-icon--days {
          background: rgba(59, 130, 246, 0.1);
          color: #3B82F6;
        }

        .dd-heatmap__stat-icon--streak {
          background: rgba(245, 158, 11, 0.1);
          color: #F59E0B;
        }

        .dd-heatmap__stat-icon--max {
          background: rgba(139, 92, 246, 0.1);
          color: #8B5CF6;
        }

        .dd-heatmap__stat-content {
          display: flex;
          flex-direction: column;
        }

        .dd-heatmap__stat-value {
          font-size: 19px;
          font-weight: 700;
          color: var(--dd-text-primary, #0F172A);
          line-height: 1.1;
        }

        .dd-heatmap__stat-label {
          font-size: 11px;
          font-weight: 650;
          letter-spacing: 0.02em;
          text-transform: uppercase;
          color: var(--dd-text-muted, #64748B);
        }

        .dd-heatmap__error {
          padding: 12px 16px;
          margin-bottom: 16px;
          background: rgba(239, 68, 68, 0.1);
          border: 1px solid rgba(239, 68, 68, 0.2);
          border-radius: 8px;
          color: #DC2626;
          font-size: 14px;
        }

        .dd-heatmap__chart {
          margin-bottom: 16px;
          padding: 14px 12px 10px;
          border-radius: 16px;
          background: color-mix(in srgb, var(--dd-bg-secondary, #F1F5F9) 90%, white);
          border: 1px solid color-mix(in srgb, var(--dd-heatmap-accent) 20%, var(--dd-border-light, rgba(203, 213, 225, 0.58)));
          box-shadow: inset 0 1px 0 rgba(255, 255, 255, 0.65);
        }

        .dd-heatmap__chart .react-calendar-heatmap {
          width: 100%;
        }

        .dd-heatmap__chart .react-calendar-heatmap rect {
          width: 8px;
          height: 8px;
          rx: 2.5;
          ry: 2.5;
          transform-box: fill-box;
          transform-origin: center;
        }

        .dd-heatmap__chart .react-calendar-heatmap rect:hover {
          transform: none;
          filter: none;
        }

        .dd-heatmap__chart .react-calendar-heatmap text {
          font-size: 9px;
          font-weight: 600;
          letter-spacing: 0.03em;
          fill: var(--dd-text-muted, #64748B);
        }

        /* Heatmap cells */
        .dd-hc {
          rx: 2.5;
          ry: 2.5;
          cursor: pointer;
          stroke: rgba(100, 116, 139, 0.28);
          stroke-width: 0.7;
          transition: stroke 0.22s cubic-bezier(0.22, 1, 0.36, 1), stroke-width 0.22s cubic-bezier(0.22, 1, 0.36, 1);
        }

        .dd-heatmap__chart .react-calendar-heatmap rect.dd-hc:hover,
        .dd-heatmap__chart .react-calendar-heatmap rect.dd-hc:focus-visible {
          stroke: #0f172a;
          stroke-width: 1.2;
          outline: none;
        }

        .dd-hc--active {
          filter: drop-shadow(0 1px 4px rgba(6, 182, 212, 0.2));
        }

        .dd-hc-0 {
          fill: #dbe4ef;
        }

        .dd-hc-1 {
          fill: #bae6fd;
        }

        .dd-hc-2 {
          fill: #7dd3fc;
        }

        .dd-hc-3 {
          fill: #38bdf8;
        }

        .dd-hc-4 {
          fill: #0284c7;
        }

        /* Legend */
        .dd-heatmap__legend {
          display: flex;
          align-items: center;
          justify-content: space-between;
          gap: 8px;
          padding: 8px 10px;
          border: 1px solid rgba(148, 163, 184, 0.22);
          border-radius: 12px;
        }

        .dd-heatmap__legend-label {
          font-size: 10px;
          font-weight: 700;
          letter-spacing: 0.06em;
          text-transform: uppercase;
          color: var(--dd-text-muted, #64748B);
        }

        .dd-heatmap__legend-scale {
          display: flex;
          gap: 6px;
          align-items: center;
        }

        .dd-heatmap__legend-box {
          width: 12px;
          height: 12px;
          border-radius: 3px;
          border: 1px solid rgba(100, 116, 139, 0.28);
        }

        /* Tooltip */
        .dd-heatmap__tooltip {
          position: fixed;
          z-index: 10000;
          min-width: 180px;
          padding: 10px 12px;
          background: color-mix(in srgb, #020617 84%, #0f172a);
          border: 1px solid rgba(148, 163, 184, 0.32);
          border-radius: 10px;
          box-shadow: 0 18px 40px rgba(2, 6, 23, 0.42);
          backdrop-filter: blur(6px);
          pointer-events: none;
          animation: dd-tooltip-fade 0.14s ease;
        }

        @keyframes dd-tooltip-fade {
          from {
            opacity: 0;
            transform: translateY(4px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        .dd-heatmap__tooltip-date {
          font-size: 13px;
          font-weight: 600;
          color: #F8FAFC;
          margin-bottom: 2px;
        }

        .dd-heatmap__tooltip-duration {
          font-size: 12px;
          color: #94A3B8;
        }

        .dd-heatmap__tooltip-intensity {
          margin-top: 4px;
          font-size: 11px;
          color: #cbd5e1;
          letter-spacing: 0.01em;
        }

        /* Dark theme */
        [data-theme="dark"] .dd-heatmap {
          background: var(--dd-bg-secondary, #1E293B);
          border-color: color-mix(in srgb, var(--dd-heatmap-accent) 28%, var(--dd-border-medium, #334155));
          box-shadow: 0 16px 34px rgba(2, 6, 23, 0.36);
        }

        [data-theme="dark"] .dd-heatmap__range-pill {
          color: #e2e8f0;
          border-color: rgba(226, 232, 240, 0.35);
        }

        [data-theme="dark"] .dd-heatmap__stat {
          border-color: rgba(100, 116, 139, 0.36);
          background: rgba(15, 23, 42, 0.35);
        }

        [data-theme="dark"] .dd-heatmap__stat:hover {
          border-color: #cbd5e1;
        }

        [data-theme="dark"] .dd-heatmap__chart {
          background: rgba(15, 23, 42, 0.56);
          border-color: rgba(56, 189, 248, 0.2);
          box-shadow: inset 0 1px 0 rgba(148, 163, 184, 0.12);
        }

        [data-theme="dark"] .dd-hc-0 {
          fill: #243447;
          stroke: rgba(100, 116, 139, 0.32);
        }

        [data-theme="dark"] .dd-hc-1 {
          fill: rgba(56, 189, 248, 0.34);
        }

        [data-theme="dark"] .dd-hc-2 {
          fill: rgba(56, 189, 248, 0.5);
        }

        [data-theme="dark"] .dd-hc-3 {
          fill: rgba(34, 211, 238, 0.72);
        }

        [data-theme="dark"] .dd-hc-4 {
          fill: #22d3ee;
        }

        [data-theme="dark"] .dd-heatmap__chart .react-calendar-heatmap rect.dd-hc:hover,
        [data-theme="dark"] .dd-heatmap__chart .react-calendar-heatmap rect.dd-hc:focus-visible {
          stroke: #e2e8f0;
        }

        [data-theme="dark"] .dd-heatmap__legend {
          border-color: rgba(100, 116, 139, 0.36);
        }

        /* Responsive */
        @media (max-width: 640px) {
          .dd-heatmap__header {
            flex-direction: column;
          }

          .dd-heatmap__range-pill {
            margin-left: 0;
          }

          .dd-heatmap__stats {
            width: 100%;
            display: grid;
            grid-template-columns: repeat(3, minmax(0, 1fr));
            gap: 8px;
          }

          .dd-heatmap__stat-content {
            display: none;
          }

          .dd-heatmap__stat-icon {
            width: 40px;
            height: 40px;
          }

          .dd-heatmap__chart {
            padding: 8px;
          }

          .dd-heatmap__chart .react-calendar-heatmap rect {
            width: 6px;
            height: 6px;
          }
        }
      `}</style>
    </div>
  );
};

export default ReadingHeatmap;
